## 🛡️ SECURE BASELINE CONFIGURATION

Here's a starter template for a secure Express.js application:

```javascript
const express = require('express');
const helmet = require('helmet');
const cors = require('cors');
const rateLimit = require('express-rate-limit');
const morgan = require('morgan');
require('dotenv').config();

const app = express();

// 1. Security Headers
app.use(helmet());

// 2. Logging
app.use(morgan('combined'));

// 3. Rate Limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
});
app.use(limiter);

// 4. CORS
app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') || ['https://localhost:3000'],
  credentials: true,
}));

// 5. Body Parsing with size limits
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ limit: '10kb' }));

// 6. Security endpoints
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// 7. Protected endpoints with auth middleware
const authenticateToken = (req, res, next) => {
  const token = req.headers['authorization']?.split(' ')[1];
  if (!token) return res.sendStatus(401);
  // Verify token...
  next();
};

app.get('/users', authenticateToken, (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
  ]);
});

// 8. 404 Handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not Found' });
});

// 9. Error Handler
app.use((err, req, res, next) => {
  const message = process.env.NODE_ENV === 'production' 
    ? 'Internal Server Error' 
    : err.message;
  res.status(err.status || 500).json({ error: message });
});

app.listen(3000, () => {
  console.log('Secure server running on port 3000');
});

module.exports = app;
```

